import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useNavigate } from 'react-router-dom';
import Home from './components/Home';
import Login from './components/Login';
import Register from './components/Register';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';

const API_URL = 'http://localhost:3001/api';

function App() {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    if (token && savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const login = (token, userData) => {
    localStorage.setItem('token', token);
    localStorage.setItem('user', JSON.stringify(userData));
    setUser(userData);
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
    navigate('/');
  };

  return (
    <div>
      <nav className="navbar">
        <div>
          <Link to="/" style={{ color: 'white', textDecoration: 'none' }}>
            <h1>🔄 GShop</h1>
          </Link>
        </div>
        <div className="nav-links">
          {user ? (
            <>
              <Link to="/dashboard">Dashboard</Link>
              <Link to="/profile">Profile</Link>
              <span className="credit-badge">💰 {user.credits} Credits</span>
              <button onClick={logout} className="btn" style={{ marginLeft: 20 }}>Logout</button>
            </>
          ) : (
            <>
              <Link to="/login">Login</Link>
              <Link to="/register">Register</Link>
            </>
          )}
        </div>
      </nav>

      <div className="container">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login API_URL={API_URL} onLogin={login} />} />
          <Route path="/register" element={<Register API_URL={API_URL} onLogin={login} />} />
          <Route path="/dashboard" element={<Dashboard API_URL={API_URL} user={user} />} />
          <Route path="/profile" element={<Profile API_URL={API_URL} user={user} />} />
        </Routes>
      </div>
    </div>
  );
}

export default App;
